<template>
	<div class="min-h-screen bg-gray-50 flex flex-col">
		<!-- Header -->
		<header class="bg-white border-b border-gray-200 sticky top-0 z-20">
			<div class="w-full px-4 sm:px-6 lg:px-8">
				<div class="flex items-center justify-between h-16">
					<div class="flex items-center gap-3">
						<LayoutGrid class="w-6 h-6 text-teal-600" />
						<h1 class="text-xl font-semibold text-gray-900">
							{{ translate("Capacity Planning") }}
						</h1>
					</div>
					<div class="flex items-center gap-3 sm:gap-4">
						<OutlinerNav />
					</div>
				</div>
			</div>
		</header>

		<!-- Page content -->
		<main class="flex-1 flex flex-col w-full px-4 sm:px-6 lg:px-8 py-4 sm:py-6">
			<CapacityPlanningHeader
				@week-change="handleWeekChange"
				@filter-change="handleFilterChange"
				@refresh="store.fetchCapacityPlan()"
			/>

			<CapacityPlanningGrid
				:employees="store.filteredEmployees"
				:week-dates="store.weekDates"
				:plan="store.plan"
				:loading="store.loading"
				@cell-click="handleCellClick"
				@delete-assignment="handleDeleteAssignment"
			/>
		</main>

		<!-- Assignment Modal -->
		<CapacityAssignmentModal
			:available-projects="availableProjects"
			v-model:show="showModal"
			:employee="modalEmployee"
			:employee-name="modalEmployeeName"
			:date="modalDate"
			:week-start="formatDate(store.currentWeekStart)"
			:week-end="store.weekEndDate"
			:current-day-total="currentDayTotal"
			:existing-assignment="modalExistingAssignment"
			@confirm="handleModalConfirm"
		/>

		<BackToDeskButton />
	</div>
</template>

<script setup>
import { ref, onMounted, computed } from "vue";
import { LayoutGrid } from "lucide-vue-next";
import { useCapacityPlanningStore } from "../stores/capacityPlanningStore";
import CapacityPlanningHeader from "../components/capacity-planning/CapacityPlanningHeader.vue";
import CapacityPlanningGrid from "../components/capacity-planning/CapacityPlanningGrid.vue";
import CapacityAssignmentModal from "../components/capacity-planning/CapacityAssignmentModal.vue";
import OutlinerNav from "@erpnext-projekt-hub/components/OutlinerNav.vue";
import BackToDeskButton from "@erpnext-projekt-hub/components/BackToDeskButton.vue";

const realWindow = typeof globalThis !== "undefined" ? globalThis.window : undefined;
const translate = (text) => {
	return typeof realWindow !== "undefined" && typeof realWindow.__ === "function"
		? realWindow.__(text)
		: text;
};

const store = useCapacityPlanningStore();

// Modal state
const showModal = ref(false);
const modalEmployee = ref(null);
const modalEmployeeName = ref("");
const modalDate = ref(null);
const modalExistingAssignment = ref(null);
const availableProjects = ref([]);

// Computed: current day total for preview
const currentDayTotal = computed(() => {
	if (!modalEmployee.value || !modalDate.value) return 0;
	const cell = store.getCellData(modalEmployee.value, modalDate.value);
	return cell.daily_total || 0;
});

// Helper: format date as YYYY-MM-DD
function formatDate(date) {
	if (!date) return null;
	const d = new Date(date);
	return d.toISOString().split("T")[0];
}

// Initialization
onMounted(async () => {
	// Fetch initial data
	// Backend will handle role check and show error if user doesn't have permission
	try {
		await store.fetchCapacityPlan();
	} catch (err) {
		console.error("Failed to load capacity plan:", err);
		// Backend will show the error via frappe.show_alert
	}
});

function handleWeekChange(direction) {
	store.navigateWeek(direction);
}

function handleFilterChange({ employee }) {
	store.setFilter("employee", employee);
}

async function handleCellClick({ employee, date, employeeName }) {
	modalEmployee.value = employee;
	modalEmployeeName.value = employeeName;
	modalDate.value = date;
	modalExistingAssignment.value = null;

	// Fetch available projects
	try {
		availableProjects.value = await store.fetchActiveProjects();
	} catch (err) {
		console.error("Failed to fetch projects:", err);
		availableProjects.value = [];
	}

	showModal.value = true;
}

function handleDeleteAssignment(assignmentId) {
	if (!window.frappe) {
		store.deleteProjectAssignment(assignmentId);
		return;
	}

	frappe.confirm(translate("Are you sure you want to delete this assignment?"), async () => {
		try {
			await store.deleteProjectAssignment(assignmentId);
		} catch (err) {
			console.error("Failed to delete assignment:", err);
		}
	});
}

async function handleModalConfirm(payload) {
	try {
		if (payload.assignmentId) {
			// Update existing assignment
			await store.updateProjectAssignment(
				payload.assignmentId,
				payload.from_date,
				payload.to_date,
				payload.hours_per_day
			);
		} else {
			// Create new assignment
			await store.createProjectAssignment(
				payload.employee,
				payload.project,
				payload.from_date,
				payload.to_date,
				payload.hours_per_day
			);
		}
	} catch (err) {
		console.error("Failed to save assignment:", err);
	}
}
</script>
