import { defineStore } from "pinia";
import { ref, computed } from "vue";

// Helper to get CSRF token
function getCsrfToken() {
	if (window.frappe && window.frappe.csrf_token && window.frappe.csrf_token !== "None") {
		return window.frappe.csrf_token;
	}
	if (window.csrf_token && window.csrf_token !== "{{ csrf_token }}") {
		return window.csrf_token;
	}
	return "";
}

// Helper for API calls with FormData
async function apiCall(method, params = {}) {
	const csrfToken = getCsrfToken();

	const formData = new FormData();
	Object.entries(params).forEach(([key, value]) => {
		if (value !== null && value !== undefined) {
			formData.append(key, value);
		}
	});

	const response = await fetch(`/api/method/${method}`, {
		method: "POST",
		headers: {
			"X-Frappe-CSRF-Token": csrfToken,
		},
		body: formData,
	});

	const data = await response.json();

	// Display server messages if present
	if (data._server_messages && window.frappe) {
		try {
			const messages = JSON.parse(data._server_messages);
			if (Array.isArray(messages)) {
				messages.forEach((msg) => {
					try {
						const msgData = JSON.parse(msg);
						if (msgData.message) {
							frappe.show_alert({
								message: msgData.message,
								indicator: msgData.indicator || "blue",
							});
						}
					} catch (e) {
						if (typeof msg === "string") {
							frappe.show_alert({ message: msg, indicator: "blue" });
						}
					}
				});
			}
		} catch (e) {
			console.error("Error parsing server messages:", e);
		}
	}

	if (!response.ok) {
		const errorMsg = data.exception || data._server_messages || "API Error";
		if (window.frappe) {
			frappe.show_alert({ message: errorMsg, indicator: "red" });
		}
		throw new Error(errorMsg);
	}
	return data.message;
}

// Helper to get Monday of current week
function getMondayOfWeek(date = new Date()) {
	const d = new Date(date);
	const day = d.getDay();
	const diff = d.getDate() - day + (day === 0 ? -6 : 1);
	return new Date(d.setDate(diff));
}

// Helper to format date as YYYY-MM-DD
function formatDate(date) {
	const d = new Date(date);
	return d.toISOString().split("T")[0];
}

// Helper for translation
function translate(text) {
	return typeof window !== "undefined" && typeof window.__ === "function"
		? window.__(text)
		: text;
}

export const useCapacityPlanningStore = defineStore("capacityPlanning", () => {
	// State
	const currentWeekStart = ref(null); // Monday of current week
	const employees = ref([]); // Available employees
	const plan = ref({}); // plan[employee][date] = {entries[], daily_total, is_overbooked}
	const loading = ref(false);
	const selectedEmployee = ref(null); // Filter

	// Initialize to current week
	if (!currentWeekStart.value) {
		currentWeekStart.value = getMondayOfWeek();
	}

	// Computed
	const weekDates = computed(() => {
		if (!currentWeekStart.value) return [];

		const dates = [];
		for (let i = 0; i < 5; i++) {
			// Mon-Fri only
			const date = new Date(currentWeekStart.value);
			date.setDate(date.getDate() + i);
			dates.push(formatDate(date));
		}
		return dates;
	});

	const weekEndDate = computed(() => {
		if (!currentWeekStart.value) return null;
		const dates = weekDates.value;
		return dates.length > 0 ? dates[dates.length - 1] : null;
	});

	const filteredEmployees = computed(() => {
		if (selectedEmployee.value) {
			const query = selectedEmployee.value.toLowerCase();
			return employees.value.filter((emp) =>
				(emp.employee_name || "").toLowerCase().includes(query)
			);
		}
		return employees.value;
	});

	// Actions
	async function fetchCapacityPlan(startDate = null) {
		loading.value = true;

		try {
			if (startDate) {
				currentWeekStart.value = new Date(startDate);
			}

			const params = {
				start_date: formatDate(currentWeekStart.value),
				end_date: formatDate(
					new Date(currentWeekStart.value.getTime() + 4 * 24 * 60 * 60 * 1000)
				), // Friday (Mon + 4 days)
			};

			const data = await apiCall(
				"projekt_hub_pro.project_hub_pro.api.capacity_planning.get_capacity_plan",
				params
			);

			if (data) {
				employees.value = data.employees || [];
				plan.value = data.plan || {};
			}
		} catch (err) {
			console.error("Failed to fetch capacity plan:", err);
			if (window.frappe) {
				frappe.show_alert({
					message: translate("Failed to load capacity plan"),
					indicator: "red",
				});
			}
		} finally {
			loading.value = false;
		}
	}

	async function createProjectAssignment(employee, project, from_date, to_date, hours_per_day) {
		try {
			const data = await apiCall(
				"projekt_hub_pro.project_hub_pro.api.capacity_planning.create_project_assignment",
				{
					employee: employee,
					project: project,
					from_date: from_date,
					to_date: to_date,
					hours_per_day: hours_per_day,
				}
			);

			if (data) {
				if (window.frappe) {
					frappe.show_alert({
						message: translate("Project assignment created successfully"),
						indicator: "green",
					});
				}

				// Refresh the plan data
				await fetchCapacityPlan();

				return data;
			}
		} catch (err) {
			console.error("Failed to create project assignment:", err);
			throw err;
		}
	}

	async function updateProjectAssignment(
		assignment_id,
		from_date = null,
		to_date = null,
		hours_per_day = null
	) {
		try {
			const params = { assignment_id: assignment_id };
			if (from_date !== null) params.from_date = from_date;
			if (to_date !== null) params.to_date = to_date;
			if (hours_per_day !== null) params.hours_per_day = hours_per_day;

			const data = await apiCall(
				"projekt_hub_pro.project_hub_pro.api.capacity_planning.update_project_assignment",
				params
			);

			if (data) {
				if (window.frappe) {
					frappe.show_alert({
						message: translate("Project assignment updated successfully"),
						indicator: "green",
					});
				}

				// Refresh the plan data
				await fetchCapacityPlan();

				return data;
			}
		} catch (err) {
			console.error("Failed to update project assignment:", err);
			throw err;
		}
	}

	async function deleteProjectAssignment(assignment_id) {
		try {
			await apiCall(
				"projekt_hub_pro.project_hub_pro.api.capacity_planning.delete_project_assignment",
				{ assignment_id: assignment_id }
			);

			if (window.frappe) {
				frappe.show_alert({
					message: translate("Project assignment deleted successfully"),
					indicator: "green",
				});
			}

			// Refresh the plan data
			await fetchCapacityPlan();
		} catch (err) {
			console.error("Failed to delete project assignment:", err);
			throw err;
		}
	}

	async function fetchActiveProjects() {
		const data = await apiCall(
			"projekt_hub_pro.project_hub_pro.api.capacity_planning.get_active_projects"
		);
		return data || [];
	}

	function navigateWeek(direction) {
		const current = new Date(currentWeekStart.value);
		if (direction === "prev") {
			current.setDate(current.getDate() - 7);
		} else if (direction === "next") {
			current.setDate(current.getDate() + 7);
		} else if (direction === "today") {
			currentWeekStart.value = getMondayOfWeek();
			fetchCapacityPlan();
			return;
		}

		currentWeekStart.value = current;
		fetchCapacityPlan();
	}

	function setFilter(key, value) {
		if (key === "employee") {
			selectedEmployee.value = value;
		}
		fetchCapacityPlan();
	}

	function clearFilters() {
		selectedEmployee.value = null;
		fetchCapacityPlan();
	}

	// Get cell data with default empty state
	function getCellData(employee, date) {
		if (plan.value[employee] && plan.value[employee][date]) {
			return plan.value[employee][date];
		}
		return {
			entries: [],
			daily_total: 0,
			is_overbooked: false,
		};
	}

	return {
		// State
		currentWeekStart,
		employees,
		plan,
		loading,
		selectedEmployee,
		// Computed
		weekDates,
		weekEndDate,
		filteredEmployees,
		// Actions
		fetchCapacityPlan,
		fetchActiveProjects,
		createProjectAssignment,
		updateProjectAssignment,
		deleteProjectAssignment,
		navigateWeek,
		setFilter,
		clearFilters,
		getCellData,
	};
});
